    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    if n < 2:
        return n
    else:
        for divisor in range(n-1, 1, -1):
            if n % divisor == 0:
                return divisor
def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    if n == 1:
        return 1

    max_divisor = n // 2

    while max_divisor > 1:
        if n % max_divisor == 0:
            return max_divisor
        max_divisor -= 1

    return 1

