    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    result = {}
    for letter in test.split(' '):
        if letter in result:
            result[letter] += 1
        else:
            result[letter] = 1

    return result
